1	// claim-office.ts
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const FIRST_INSURANCE_PERCENT = 110;
13	const PROCESSING_FEE = 5;
14	
15	type Item = { type: string };
16	
17	const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
18	const BLOCK_OF_3_BASE_PREMIUM = 60;
19	const BLOCK_OF_3_SIZE = 3;
20	
21	const isBlockOf3Components = (type: string, count: number): boolean =>
22	  COMPONENT_TYPES.has(type) && count === BLOCK_OF_3_SIZE;
23	
24	const baseForGroup = (type: string, count: number): number =>
25	  isBlockOf3Components(type, count)
26	    ? BLOCK_OF_3_BASE_PREMIUM
27	    : BASE_PREMIUMS[type] * count;
28	
29	const countItemsByType = (items: Item[]): Record<string, number> => {
30	  const counts: Record<string, number> = {};
31	  for (const item of items) {
32	    counts[item.type] = (counts[item.type] ?? 0) + 1;
33	  }
34	  return counts;
35	};
36	
37	const quotePremium = (items: Item[]): number => {
38	  const countsByType = countItemsByType(items);
39	  let baseTotal = 0;
40	  for (const [type, count] of Object.entries(countsByType)) {
41	    baseTotal += baseForGroup(type, count);
42	  }
43	  const withFirstInsurance = (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
44	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
45	};
46	
47	export function processScenario(scenario: any): unknown {
48	  const [{ items }] = scenario.steps;
49	  return { results: [{ premium: quotePremium(items) }] };
50	}
